return [{
  json: {
  "__source": "gmail",
  "subject": "Boutique Hotel Website Quote",
  "from": {
    "text": "\"Kasun Perera\" <kasun@hotelceylon.lk>"
  },
  "textPlain": "Hi Silva & Co, I need an official quote for building an ecommerce website for our boutique hotel in Colombo. We need an online booking system and a high-res room gallery. What are your standard packages and pricing?",
  "threadId": "gm_thread_112233",
  "date": "2026-05-16T10:15:00.000Z",
  "headers": {
    "message-id": "<gm_thread_112233@mail.gmail.com>",
    "in-reply-to": "",
    "list-unsubscribe": "",
    "auto-submitted": "",
    "subject": "Boutique Hotel Website Quote",
    "from": "\"Kasun Perera\" <kasun@hotelceylon.lk>"
  }
},
}];

function stripHtml(html) {
  if (!html || typeof html !== "string") return "";
  return html
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, " ")
    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function stripSignatureAndQuotes(text) {
  if (!text || typeof text !== "string") return "";
  let t = text.replace(/\r\n/g, "\n");

  const idx = t.search(/^On .+ wrote:\s*$/im);
  if (idx !== -1) t = t.slice(0, idx).trim();

  const sigDash = t.split(/^--\s*$/m);
  if (sigDash.length > 1) t = sigDash[0].trim();

  const sentFrom = t.split(/^Sent from my .+$/im);
  if (sentFrom.length > 1) t = sentFrom[0].trim();

  return t.trim();
}

function valueText(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "string") return value;
  if (typeof value.text === "string") return value.text;
  if (typeof value.value === "string") return value.value;
  if (Array.isArray(value) && value[0]) return valueText(value[0]);
  return String(value || "");
}

function parseFromHeader(from) {
  const text = valueText(from).trim();
  if (!text) return { customer_name: "", customer_email_or_phone: "" };

  const angled = /^\s*"?([^"<]*?)"?\s*<\s*([^>]+)\s*>\s*$/;
  const m = text.match(angled);
  if (m) {
    const name = (m[1] || "").replace(/^"|"$/g, "").trim();
    const email = (m[2] || "").trim().toLowerCase();
    return {
      customer_name: name || titleCaseFromEmail(email),
      customer_email_or_phone: email,
    };
  }

  const bare = text.match(/^([\w.!#$%&'*+/=?^`{|}~-]+@[\w.-]+\.[A-Za-z]{2,})$/);
  if (bare) {
    const email = bare[1].toLowerCase();
    return {
      customer_name: titleCaseFromEmail(email),
      customer_email_or_phone: email,
    };
  }

  return { customer_name: text, customer_email_or_phone: "" };
}

function titleCaseFromEmail(email) {
  const local = (email || "").split("@")[0] || "";
  return local
    .replace(/[._-]+/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase())
    .trim();
}

function parseHeaders(raw) {
  const headers = raw.headers || raw.header || {};
  if (headers && typeof headers === "object" && !Array.isArray(headers)) {
    return Object.fromEntries(
      Object.entries(headers).map(([k, v]) => [String(k).toLowerCase(), valueText(v)]),
    );
  }
  if (Array.isArray(raw.headerLines)) {
    const out = {};
    for (const line of raw.headerLines) {
      const idx = String(line).indexOf(":");
      if (idx > 0) out[String(line).slice(0, idx).trim().toLowerCase()] = String(line).slice(idx + 1).trim();
    }
    return out;
  }
  return {};
}

function unwrapBody(payload) {
  if (payload && typeof payload === "object" && payload.body) return payload.body;
  return payload;
}

function stripAngleId(v) {
  return String(v || "").replace(/[<>]/g, "").trim();
}

function threadKey(raw, headers) {
  if (raw.threadId) return String(raw.threadId);
  if (raw.thread_id) return String(raw.thread_id);
  if (raw.id) return `gmail:${raw.id}`;
  if (headers["in-reply-to"]) return `msg:${stripAngleId(headers["in-reply-to"])}`;
  if (headers["message-id"]) return `msg:${stripAngleId(headers["message-id"])}`;
  return null;
}

function detectSource(rawInput) {
  const raw = unwrapBody(rawInput) || {};
  const explicit = raw.__source || raw.source;
  if (explicit && ["gmail", "demo"].includes(String(explicit).toLowerCase())) {
    return String(explicit).toLowerCase();
  }
  if (raw.customer_email && raw.message) return "demo";
  if (
    raw.from ||
    raw.From ||
    raw.subject ||
    raw.textPlain !== undefined ||
    raw.text !== undefined ||
    raw.html !== undefined ||
    raw.textHtml !== undefined
  ) {
    return "gmail";
  }
  throw new Error("multi_channel_normalizer: could not detect gmail or demo payload");
}

function parseGmail(rawInput) {
  const raw = unwrapBody(rawInput) || {};
  const headers = parseHeaders(raw);
  const fromField = raw.from || raw.From || headers.from || "";
  const { customer_name, customer_email_or_phone } = parseFromHeader(fromField);

  let body =
    valueText(raw.textPlain) ||
    valueText(raw.text) ||
    valueText(raw.textAsHtml) ||
    valueText(raw.textHtml);
  if (!body && raw.html) body = stripHtml(valueText(raw.html));
  if (raw.textAsHtml && body === valueText(raw.textAsHtml)) body = stripHtml(body);
  if (raw.textHtml && body === valueText(raw.textHtml)) body = stripHtml(body);

  const message = stripSignatureAndQuotes(body);
  const subject = valueText(raw.subject || headers.subject);
  const dateValue = raw.date || raw.dateUtc || raw.internalDate || raw.receivedDate || new Date().toISOString();
  const receivedAt = typeof dateValue === "number" ? new Date(dateValue).toISOString() : new Date(dateValue).toISOString();

  return {
    source: "gmail",
    customer_name,
    customer_email_or_phone,
    message,
    external_thread_id: threadKey(raw, headers),
    received_at: receivedAt,
    raw_payload: rawInput,
    _filter: {
      from_header: valueText(fromField),
      subject,
      list_unsubscribe: !!(headers["list-unsubscribe"] || headers["list_unsubscribe"]),
      auto_submitted: headers["auto-submitted"] || headers["auto_submitted"] || "",
      has_attachment: !!(raw.attachments && raw.attachments.length),
      body_for_rules: message,
    },
  };
}

function parseDemo(rawInput) {
  const raw = unwrapBody(rawInput) || {};
  return {
    source: raw.source || "demo",
    customer_name: String(raw.customer_name || "").trim(),
    customer_email_or_phone: String(raw.customer_email || raw.customer_email_or_phone || "").trim().toLowerCase(),
    message: String(raw.message || "").trim(),
    external_thread_id: raw.threadId || raw.thread_id || null,
    received_at: raw.received_at || new Date().toISOString(),
    raw_payload: rawInput,
    _filter: {
      from_header: raw.customer_email || "",
      subject: raw.subject || "",
      list_unsubscribe: false,
      auto_submitted: "",
      has_attachment: false,
      body_for_rules: String(raw.message || "").trim(),
    },
  };
}

function normalizeItem(raw) {
  const source = detectSource(raw);
  if (source === "gmail") return parseGmail(raw);
  if (source === "demo") return parseDemo(raw);
  throw new Error(`multi_channel_normalizer: unsupported source "${source}"`);
}

if (typeof $input !== "undefined") {
  return $input.all().map(({ json }) => ({ json: normalizeItem(json) }));
}

const AUTOMATED_LOCAL = new RegExp(
  String.raw`^(no-?reply|noreply|do-not-reply|mailer-daemon|notifications?|notify|alerts?|news(letters?)?|updates?|info|hello|support)(?:$|[.\-_])`,
  "i",
);

const PLEASANTRY = /^(thanks?|thx|ty|ok|okay|got\s+it|cheers|noted|👍|🙏)\b\.?[!.']*$/iu;

const OFFICE_SUBJ = /^(out of office|automatic reply|vacation)\b/i;

const SPAM_LEX = ["free", "win", "click here", "prize", "viagra", "crypto", "$$$"];

function tokenCount(s) {
  return s
    .trim()
    .split(/\s+/)
    .filter(Boolean).length;
}

function hasQuestion(body) {
  return typeof body === "string" && body.includes("?");
}

function normBody(message, filter) {
  const b = (filter && filter.body_for_rules) || message || "";
  return String(b).trim();
}

function drop(reason, normalized) {
  return {
    json: {
      keep: false,
      drop_reason: reason,
      normalized,
    },
  };
}

function keep(normalized) {
  return {
    json: {
      keep: true,
      drop_reason: null,
      ...normalized,
    },
  };
}

function evaluateNoiseFilter(normalized) {
  const f = normalized._filter || {};
  const body = normBody(normalized.message, f);
  const fromHeader = String(f.from_header || "").toLowerCase();
  const subject = String(f.subject || "");

  // Extract rough "local part" and domain for Gmail-ish heuristics
  const emailMatch = fromHeader.match(/<([^>]+)>\s*$/);
  const addr = (emailMatch ? emailMatch[1] : fromHeader).trim();
  const at = addr.lastIndexOf("@");
  const localPart = at > 0 ? addr.slice(0, at) : addr;
  const domain = at > 0 ? addr.slice(at + 1) : "";

  if (normalized.source === "gmail") {
    if (
      (AUTOMATED_LOCAL.test(localPart) || AUTOMATED_LOCAL.test(domain)) &&
      !hasQuestion(body)
    ) {
      return drop("automated_sender_no_question", normalized);
    }

    if (OFFICE_SUBJ.test(subject)) {
      return drop("auto_reply_subject", normalized);
    }

    const autoSub = String(f.auto_submitted || "").toLowerCase();
    if (autoSub.includes("auto-replied")) {
      return drop("auto_submitted_header", normalized);
    }

    if (f.list_unsubscribe) {
      return drop("list_unsubscribe_header", normalized);
    }

    if (
      /\bunsubscribe\b/i.test(body) &&
      /\bhttps?:\/\//i.test(body.slice(0, 80))
    ) {
      return drop("newsletter_unsubscribe_body", normalized);
    }
  }

  const tokens = tokenCount(body);
  if (tokens <= 3 && tokens > 0 && PLEASANTRY.test(body)) {
    return drop("short_pleasantry", normalized);
  }

  if (body.length < 8 && !f.has_attachment) {
    return drop("body_too_short", normalized);
  }

  let spamHits = 0;
  const low = body.toLowerCase();
  for (const w of SPAM_LEX) {
    if (low.includes(w)) spamHits++;
  }
  if (spamHits >= 3) {
    return drop("spam_keyword_density", normalized);
  }

  return keep(normalized);
}

// --- n8n entrypoint ---
return $input.all().map(({ json }) => evaluateNoiseFilter(json));

const normalized = $input.first().json;
const id = normalized.customer_email_or_phone || '';
if (!id) throw new Error('DedupLookupQuery: missing customer_email_or_phone');
const variants = [...new Set([id, id.toLowerCase()].filter(Boolean))];
const orInner = variants.map((v) => 'customer_email.eq.' + encodeURIComponent(v)).join(',');
const lookup_path =
  '?select=id,status,updated_at' +
  '&status=in.(new,in_progress,awaiting_reply)' +
  '&or=(' + orInner + ')' +
  '&order=updated_at.desc&limit=1';
return [{ json: { lookup_path, normalized } }];

const response = $input.first().json;
const rows = Array.isArray(response)
  ? response
  : Array.isArray(response.body)
    ? response.body
    : response && response.id
      ? [response]
      : [];
const normalized = $('Multi-Channel Normalizer').first().json;
const hit = Array.isArray(rows) && rows[0] && rows[0].id;
if (hit) {
  return [{ json: { action: 'append_conversation', lead_id: rows[0].id, normalized } }];
}
return [{ json: { action: 'create_new_lead', normalized } }];

